const express = require('express');
const fs = require('fs').promises;
const path = require('path');
const vm = require('vm');
const crypto = require('crypto');

class APIGateway {
  constructor(config) {
    this.app = express();
    this.config = config;
    this.plugins = [];
    this.middlewareStack = [];
    this.init();
  }

  async init() {
    this.app.use(express.json());
    this.app.use(express.urlencoded({ extended: true }));
    
    await this.loadPlugins();
    this.setupMiddleware();
    this.setupRoutes();
  }

  async loadPlugins() {
    const pluginSources = [];
    
    if (this.config.plugins?.fromFiles) {
      for (const file of this.config.plugins.fromFiles) {
        try {
          const pluginCode = await fs.readFile(file, 'utf8');
          pluginSources.push({ code: pluginCode, source: 'file' });
        } catch (error) {
          console.error(`Failed to load plugin from file ${file}:`, error);
        }
      }
    }

    if (this.config.plugins?.fromEnv) {
      for (const envVar of this.config.plugins.fromEnv) {
        const pluginCode = process.env[envVar];
        if (pluginCode) {
          pluginSources.push({ code: pluginCode, source: 'env' });
        }
      }
    }

    for (const { code, source } of pluginSources) {
      try {
        const plugin = this.createSecurePlugin(code, source);
        if (plugin) {
          this.plugins.push(plugin);
          this.middlewareStack.push(plugin.middleware);
        }
      } catch (error) {
        console.error('Failed to load plugin:', error);
      }
    }
  }

  createSecurePlugin(code, source) {
    const sandbox = {
      console,
      require: (module) => {
        if (this.config.allowedModules?.includes(module)) {
          return require(module);
        }
        throw new Error(`Module ${module} not allowed`);
      },
      setTimeout,
      clearTimeout,
      setInterval,
      clearInterval,
      Buffer,
      process: {
        env: {},
        version: process.version,
        platform: process.platform
      },
      exports: {},
      module: {},
      __filename: '',
      __dirname: ''
    };

    const script = new vm.Script(code, {
      filename: `plugin-${source}-${Date.now()}`,
      timeout: 5000
    });

    try {
      const context = vm.createContext(sandbox);
      script.runInContext(context, {
        timeout: 5000,
        displayErrors: true
      });

      const plugin = sandbox.exports || {};
      
      if (typeof plugin.middleware !== 'function') {
        throw new Error('Plugin must export a middleware function');
      }

      return plugin;
    } catch (error) {
      console.error('Plugin execution error:', error);
      return null;
    }
  }

  setupMiddleware() {
    this.app.use((req, res, next) => {
      const startTime = Date.now();
      
      const originalSend = res.send;
      const originalJson = res.json;
      
      res.send = function(data) {
        const responseTime = Date.now() - startTime;
        res.set('X-Response-Time', `${responseTime}ms`);
        return originalSend.call(this, data);
      };
      
      res.json = function(data) {
        const responseTime = Date.now() - startTime;
        res.set('X-Response-Time', `${responseTime}ms`);
        return originalJson.call(this, data);
      };
      
      next();
    });

    this.middlewareStack.forEach(middleware => {
      this.app.use(middleware);
    });
  }

  setupRoutes() {
    this.app.all('*', (req, res, next) => {
      const originalSend = res.send;
      const originalJson = res.json;
      
      res.send = function(data) {
        return originalSend.call(this, data);
      };
      
      res.json = function(data) {
        return originalJson.call(this, data);
      };
      
      next();
    });
  }

  start(port = 3000) {
    return new Promise((resolve) => {
      const server = this.app.listen(port, () => {
        console.log(`API Gateway listening on port ${port}`);
        resolve(server);
      });
    });
  }

  async stop() {
    // Cleanup logic if needed
  }
}

module.exports = APIGateway;